-- =====================================================================
--  Chart of Accounts (COA) master — MoM Day1 §2.7 (ขอ Account Code จาก MGC)
--  ใช้สำหรับ Account Mapping: ผูก GL Account ตอน Post JE แล้วส่งไป NetSuite
--  Source: 01. ERP_COA_20260403.xlsx (1643 บัญชี, 21 บริษัท)
--  หมายเหตุ: ยังไม่แสดงเมนู (hidden) — ใช้ป้อน dropdown GL ในแท็บ Accounting
-- =====================================================================
create table if not exists gl_accounts (
  id           uuid primary key default gen_random_uuid(),
  company      text,            -- Apply for (MGC / MAG / SHA / ...)
  code         text not null,   -- Account code ERP
  name         text not null,   -- Account name ERP
  fs_no        text,
  fs_name      text,
  fs_group     text,
  conso_group  text,
  nfs_group    text,
  inactive     boolean not null default false,
  created_at   timestamptz not null default now()
);
create index if not exists idx_gl_accounts_code on gl_accounts(code);
create index if not exists idx_gl_accounts_company on gl_accounts(company);
alter table gl_accounts enable row level security;
do $$ begin
  create policy anon_all_gl_accounts on gl_accounts for all using (true) with check (true);
exception when duplicate_object then null; end $$;

